    if u == t:
        return f
    while ptr[u] < len(g[u]):
        e = g[u][ptr[u]]
        if e.cap > 0 and level[e.to] == level[u] + 1:
            pushed = send(g, level, ptr, e.to, t, min(f, e.cap))
            if pushed:
                e.cap -= pushed
                g[e.to][e.rev].cap += pushed
                return pushed
        ptr[u] += 1
    return 0

