def extract_one_path(g, s, t):
    path = [s]
    u = s
    while u != t:
        for e in g[u]:
            if e.cap == 0:
                u = e.to
                path.append(u)
                break
    return path

def extract_one_path(g, s, t):
    n = len(g)
    path = []
    def dfs(u):
        path.append(u)
        if u == t:
            return True
        for e in g[u]:
            if e.cap > 0:
                e.cap -= 1
                if dfs(e.to):
                    return True
                e.cap += 1
        path.pop()
        return False
    dfs(s)
    return path

